import React, { useState } from 'react';

interface ToggleProps {
  initialState?: boolean;
  onToggle?: (isOn: boolean) => void;
}

function Toggle({ initialState = false, onToggle }: ToggleProps): JSX.Element {
  const [isOn, setIsOn] = useState(initialState);

  const handleToggle = () => {
    const newState = !isOn;
    setIsOn(newState);
    if (onToggle) {
      onToggle(newState);
    }
  };

  return (
    <div>
      <button
        onClick={handleToggle}
        style={{
          backgroundColor: isOn ? '#4CAF50' : '#f44336',
          color: 'white',
          padding: '10px 20px',
          border: 'none',
          borderRadius: '4px',
          cursor: 'pointer',
          fontSize: '16px',
          fontWeight: 'bold',
        }}
      >
        {isOn ? 'ON' : 'OFF'}
      </button>
    </div>
  );
}

export default Toggle;

