import React, { useReducer } from 'react';

type CounterAction = { type: 'INCREMENT' } | { type: 'DECREMENT' } | { type: 'RESET' };
interface CounterState {
  count: number;
}

function createCounterReducer(initialCount: number) {
  return function counterReducer(state: CounterState, action: CounterAction): CounterState {
    switch (action.type) {
      case 'INCREMENT':
        return { count: state.count + 1 };
      case 'DECREMENT':
        return { count: state.count - 1 };
      case 'RESET':
        return { count: initialCount };
      default:
        return state;
    }
  };
}

interface CounterProps {
  initialCount?: number;
}

function Counter({ initialCount = 0 }: CounterProps): JSX.Element {
  const reducer = createCounterReducer(initialCount);
  const [state, dispatch] = useReducer(reducer, { count: initialCount });

  return (
    <div>
      <p>Count: {state.count}</p>
      <button onClick={() => dispatch({ type: 'INCREMENT' })}>+</button>
      <button onClick={() => dispatch({ type: 'DECREMENT' })}>-</button>
      <button onClick={() => dispatch({ type: 'RESET' })}>Reset</button>
    </div>
  );
}

export default Counter;

