  // 2. Keep the latest `handler` in a ref too, updated every render, so the
  //    event listener always calls the current handler without needing to
  //    re-attach on every render
  // 3. useEffect (runs once, empty deps): attach mousedown AND touchstart
  //    listeners on `document`; inside, check ref.current exists and does NOT
  //    contain event.target before calling the latest handler
  // 4. Clean up both listeners on unmount

  return useRef(null) as React.RefObject<T>; // replace with real implementation
}

solution:
function useClickOutside<T extends HTMLElement>(
  handler: (event: MouseEvent | TouchEvent) => void
): React.RefObject<T> {
  const ref = useRef<T>(null);
  const handlerRef = useRef(handler);

  useEffect(() => {
    handlerRef.current = handler;
  }, [handler]);

  useEffect(() => {
    function listener(event: MouseEvent | TouchEvent) {
      const el = ref.current;
      if (!el || el.contains(event.target as Node)) {
        return;
      }
      handlerRef.current(event);
    }

    document.addEventListener('mousedown', listener);
    document.addEventListener('touchstart', listener);

    return () => {
      document.removeEventListener('mousedown', listener);
      document.removeEventListener('touchstart', listener);
    };
  }, []);

  return ref as React.RefObject<T>;
}

