function useThrottle<T>(value: T, interval: number): T {
  // 1. State for the throttled value, initialized to `value`
  // 2. Refs to track: the timestamp of the last update, and a pending timeout id
  // 3. useEffect on [value, interval]:
  //    - compute time elapsed since last update
  //    - if elapsed >= interval: update immediately (leading/window-reset case),
  //      record new lastUpdate timestamp, clear any pending trailing timer
  //    - else: schedule (or reschedule) a timeout for the REMAINING time so the
  //      trailing update fires exactly when the window closes, using the latest value
  // 4. Clean up the pending timeout on unmount / before the next effect run

  return value; // replace with real implementation
}

solution:
function useThrottle<T>(value: T, interval: number): T {
  const [throttledValue, setThrottledValue] = useState<T>(value);
  const lastUpdateRef = useRef<number>(Date.now());
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const now = Date.now();
    const elapsed = now - lastUpdateRef.current;

    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }

    if (elapsed >= interval) {
      lastUpdateRef.current = now;
      setThrottledValue(value);
    } else {
      const remaining = interval - elapsed;
      timeoutRef.current = setTimeout(() => {
        lastUpdateRef.current = Date.now();
        setThrottledValue(value);
        timeoutRef.current = null;
      }, remaining);
    }

    return () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, [value, interval]);

  return throttledValue;
}

