import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';

interface FetchState<T> {
  data: T | null;
  loading: boolean;
  error: Error | null;
}

interface UseFetchOptions {
  headers?: Record<string, string>;
  method?: 'GET' | 'POST' | 'PUT' | 'DELETE';
  body?: any;
  cache?: boolean;
}

const globalCache = new Map<string, { data: any; timestamp: number }>();
const CACHE_DURATION = 5 * 60 * 1000; // 5 minutes

function useFetch<T = any>(url: string, options?: UseFetchOptions) {
  const [state, setState] = useState<FetchState<T>>({
    data: null,
    loading: true,
    error: null
  });

  const abortControllerRef = useRef<AbortController | null>(null);
  const isMountedRef = useRef(true);
  const urlRef = useRef(url);
  const optionsRef = useRef(options);

  const getCacheKey = useCallback(() => {
    return `${url}_${JSON.stringify(options || {})}`;
  }, [url, options]);

  const getCachedData = useCallback(() => {
    if (!options?.cache) return null;

    const cacheKey = getCacheKey();
    const cached = globalCache.get(cacheKey);

    if (cached && Date.now() - cached.timestamp < CACHE_DURATION) {
      return cached.data;
    }

    if (cached) {
      globalCache.delete(cacheKey);
    }

    return null;
  }, [getCacheKey, options?.cache]);

  const setCachedData = useCallback((data: T) => {
    if (!options?.cache) return;

    const cacheKey = getCacheKey();
    globalCache.set(cacheKey, {
      data,
      timestamp: Date.now()
    });
  }, [getCacheKey, options?.cache]);

  const refetch = useCallback(async () => {
    // Cancel previous request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    try {
      setState(prev => ({ ...prev, loading: true, error: null }));

      const cachedData = getCachedData();
      if (cachedData) {
        if (isMountedRef.current) {
          setState({
            data: cachedData,
            loading: false,
            error: null
          });
        }
        return;
      }

      const fetchOptions: RequestInit = {
        signal,
        headers: {
          'Content-Type': 'application/json',
          ...(options?.headers || {})
        },
        method: options?.method || 'GET'
      };

      if (options?.body) {
        fetchOptions.body = JSON.stringify(options.body);
      }

      const response = await fetch(url, fetchOptions);

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const data: T = await response.json();

      if (!isMountedRef.current) return;

      setCachedData(data);

      setState({
        data,
        loading: false,
        error: null
      });
    } catch (error) {
      if (error instanceof DOMException && error.name === 'AbortError') {
        // Request was cancelled, don't update state
        return;
      }

      if (isMountedRef.current) {
        setState({
          data: null,
          loading: false,
          error: error instanceof Error ? error : new Error(String(error))
        });
      }
    }
  }, [url, options, getCachedData, setCachedData]);

  useEffect(() => {
    isMountedRef.current = true;
    refetch();

    return () => {
      isMountedRef.current = false;
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [url, refetch]);

  // Return memoized values to prevent unnecessary re-renders of consumers
  return useMemo(() => ({
    data: state.data,
    loading: state.loading,
    error: state.error,
    refetch
  }), [state.data, state.loading, state.error, refetch]);
}

export default useFetch;

