import React, { createContext, useContext, useCallback, useMemo, useState, useRef, ReactNode, useEffect } from 'react';

interface ValidationRule {
  validate: (value: any) => boolean | Promise<boolean>;
  message: string;
}

interface FieldState {
  value: any;
  error: string | null;
  touched: boolean;
  validating: boolean;
}

interface FormContextValue {
  values: Record<string, any>;
  errors: Record<string, string | null>;
  touched: Record<string, boolean>;
  validating: Record<string, boolean>;
  setFieldValue: (name: string, value: any) => void;
  setFieldTouched: (name: string, touched: boolean) => void;
  registerField: (name: string, initialValue: any, rules: ValidationRule[]) => void;
  unregisterField: (name: string) => void;
  subscribeToField: (name: string, callback: () => void) => () => void;
  handleSubmit: (callback: (values: Record<string, any>) => void | Promise<void>) => (e: React.FormEvent) => Promise<void>;
}

const FormContext = createContext<FormContextValue | null>(null);

export function Form({ initialValues, onSubmit, children }: { initialValues: Record<string, any>; onSubmit: (values: Record<string, any>) => void | Promise<void>; children: ReactNode }) {
  const [values, setValues] = useState(initialValues);
  const [errors, setErrors] = useState<Record<string, string | null>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [validating, setValidating] = useState<Record<string, boolean>>({});
  const fieldsRef = useRef<Record<string, { rules: ValidationRule[] }>>({});
  const subscriptionsRef = useRef<Record<string, Set<() => void>>>({});
  const abortControllersRef = useRef<Record<string, AbortController>>({});
  const debounceTimersRef = useRef<Record<string, NodeJS.Timeout>>({});

  const validateField = useCallback(async (name: string, value: any) => {
    const fieldRules = fieldsRef.current[name]?.rules || [];
    const errors: string[] = [];
    setValidating(prev => ({ ...prev, [name]: true }));

    // Abort previous validation
    if (abortControllersRef.current[name]) {
      abortControllersRef.current[name].abort();
    }
    abortControllersRef.current[name] = new AbortController();
    const signal = abortControllersRef.current[name].signal;

    for (const rule of fieldRules) {
      if (signal.aborted) break;
      try {
        const isValid = await Promise.resolve(rule.validate(value));
        if (!isValid) {
          errors.push(rule.message);
          break;
        }
      } catch (e) {
        if (!signal.aborted) {
          errors.push(rule.message);
        }
      }
    }

    if (!signal.aborted) {
      setErrors(prev => ({
        ...prev,
        [name]: errors.length > 0 ? errors[0] : null,
      }));
      setValidating(prev => ({ ...prev, [name]: false }));
    }
  }, []);

  const notifyFieldSubscribers = useCallback((name: string) => {
    const callbacks = subscriptionsRef.current[name];
    if (callbacks) {
      callbacks.forEach(cb => cb());
    }
  }, []);

  const setFieldValue = useCallback((name: string, value: any) => {
    setValues(prev => ({
      ...prev,
      [name]: value,
    }));

    // Debounce validation
    if (debounceTimersRef.current[name]) {
      clearTimeout(debounceTimersRef.current[name]);
    }

    debounceTimersRef.current[name] = setTimeout(() => {
      validateField(name, value);
      notifyFieldSubscribers(name);
    }, 300);
  }, [validateField, notifyFieldSubscribers]);

  const setFieldTouched = useCallback((name: string, touched: boolean) => {
    setTouched(prev => ({
      ...prev,
      [name]: touched,
    }));
    notifyFieldSubscribers(name);
  }, [notifyFieldSubscribers]);

  const registerField = useCallback((name: string, initialValue: any, rules: ValidationRule[]) => {
    fieldsRef.current[name] = { rules };
    if (!(name in values)) {
      setValues(prev => ({
        ...prev,
        [name]: initialValue,
      }));
    }
    subscriptionsRef.current[name] = new Set();
  }, [values]);

  const unregisterField = useCallback((name: string) => {
    delete fieldsRef.current[name];
    delete subscriptionsRef.current[name];
    if (abortControllersRef.current[name]) {
      abortControllersRef.current[name].abort();
    }
  }, []);

  const subscribeToField = useCallback((name: string, callback: () => void) => {
    if (!subscriptionsRef.current[name]) {
      subscriptionsRef.current[name] = new Set();
    }
    subscriptionsRef.current[name].add(callback);
    return () => {
      subscriptionsRef.current[name].delete(callback);
    };
  }, []);

  const handleSubmit = useCallback((callback: (values: Record<string, any>) => void | Promise<void>) => async (e: React.FormEvent) => {
    e.preventDefault();
    await callback(values);
  }, [values]);

  const value: FormContextValue = useMemo(() => ({
    values,
    errors,
    touched,
    validating,
    setFieldValue,
    setFieldTouched,
    registerField,
    unregisterField,
    subscribeToField,
    handleSubmit,
  }), [values, errors, touched, validating, setFieldValue, setFieldTouched, registerField, unregisterField, subscribeToField, handleSubmit]);

  return (
    <FormContext.Provider value={value}>
      <form onSubmit={handleSubmit(onSubmit)}>
        {children}
      </form>
    </FormContext.Provider>
  );
}

function useFormContext() {
  const context = useContext(FormContext);
  if (!context) {
    throw new Error('useFormContext must be used within Form component');
  }
  return context;
}

Form.Field = function Field({ name, children }: { name: string; children: ReactNode }) {
  const { registerField, unregisterField } = useFormContext();
  const [, forceUpdate] = useState({});

  useEffect(() => {
    registerField(name, '', []);
    return () => unregisterField(name);
  }, [name, registerField, unregisterField]);

  useEffect(() => {
    const unsubscribe = useFormContext().subscribeToField(name, () => {
      forceUpdate({});
    });
    return unsubscribe;
  }, [name]);

  return (
    <fieldset>
      {children}
    </fieldset>
  );
};

Form.Input = function Input({ type = 'text', ...props }: React.InputHTMLAttributes<HTMLInputElement>) {
  const context = useFormContext();
  const name = props.name as string;
  const [, forceUpdate] = useState({});

  useEffect(() => {
    const unsubscribe = context.subscribeToField(name, () => {
      forceUpdate({});
    });
    return unsubscribe;
  }, [name, context]);

  return (
    <input
      type={type}
      value={context.values[name] || ''}
      onChange={(e) => context.setFieldValue(name, e.target.value)}
      onBlur={() => context.setFieldTouched(name, true)}
      {...props}
    />
  );
};

Form.Error = function Error() {
  const context = useFormContext();
  const { name } = useContext(FieldContext) || {};
  const [, forceUpdate] = useState({});

  useEffect(() => {
    if (!name) return;
    const unsubscribe = context.subscribeToField(name, () => {
      forceUpdate({});
    });
    return unsubscribe;
  }, [name, context]);

  if (!name || !context.errors[name] || !context.touched[name]) {
    return null;
  }

  return <span style={{ color: 'red' }}>{context.errors[name]}</span>;
};

Form.Label = function Label({ children, htmlFor }: { children: ReactNode; htmlFor?: string }) {
  return <label htmlFor={htmlFor}>{children}</label>;
};

Form.Submit = function Submit({ children }: { children: ReactNode }) {
  return <button type="submit">{children}</button>;
};

const FieldContext = createContext<{ name: string } | null>(null);

export function useForm(options: {
  initialValues: Record<string, any>;
  onSubmit: (values: Record<string, any>) => void | Promise<void>;
  validate?: (values: Record<string, any>) => Record<string, string | null>;
}) {
  const [values, setValues] = useState(options.initialValues);
  const [errors, setErrors] = useState<Record<string, string | null>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [validating, setValidating] = useState<Record<string, boolean>>({});
  const debounceTimersRef = useRef<Record<string, NodeJS.Timeout>>({});

  const validateForm = useCallback((vals: Record<string, any>) => {
    if (options.validate) {
      const errs = options.validate(vals);
      setErrors(errs);
      return Object.values(errs).every(e => e === null);
    }
    return true;
  }, [options]);

  const setFieldValue = useCallback((name: string, value: any) => {
    setValues(prev => ({
      ...prev,
      [name]: value,
    }));

    if (debounceTimersRef.current[name]) {
      clearTimeout(debounceTimersRef.current[name]);
    }

    debounceTimersRef.current[name] = setTimeout(() => {
      validateForm({ ...values, [name]: value });
    }, 300);
  }, [values, validateForm]);

  const handleSubmit = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm(values)) {
      await options.onSubmit(values);
    }
  }, [values, validateForm, options]);

  return {
    values,
    errors,
    touched,
    validating,
    setFieldValue,
    handleSubmit,
  };
}

export function FormConsumer({ children }: { children: (context: FormContextValue) => ReactNode }) {
  const context = useFormContext();
  return <>{children(context)}</>;
}
